    // Since a <= b, we have a^3 + a^3 <= a^3 + b^3 <= n, so 2*a^3 <= n, which means a^3 <= n/2.
    // Similarly, b^3 <= n, so b <= n^(1/3).

    // Maximum possible value for b is floor(n^(1/3)).
    // Since n <= 10^9, n^(1/3) <= 1000.
    const maxB = Math.floor(Math.pow(n, 1/3));

    // We iterate over a and b such that 1 <= a <= b and a^3 + b^3 <= n.

    // Iterate over 'a' starting from 1.
    // Since a <= b, we must have 2*a^3 <= a^3 + b^3 <= n, so a^3 <= n/2.
    const maxA = Math.floor(Math.pow(n / 2, 1/3));

    for (let a = 1; a <= maxA; a++) {
        const aCubed = a * a * a;

        // Iterate over 'b' starting from 'a' (since a <= b).
        // We need aCubed + b^3 <= n, so b^3 <= n - aCubed.
        const maxBCubed = n - aCubed;
        const maxBForA = Math.floor(Math.pow(maxBCubed, 1/3));

        for (let b = a; b <= maxBForA; b++) {
            const bCubed = b * b * b;
            const sum = aCubed + bCubed;

            if (sum > n) {
